from django.shortcuts import render, get_object_or_404
from django.views import View
from django.db.models import Q
from .models import Barco, Categoria


class BarcoListView(View):
    """Vista para listar barcos con búsqueda y filtros."""

    def get(self, request):
        barcos = Barco.objects.all()
        categorias = Categoria.objects.all()
        search_query = request.GET.get('search', '')
        categoria_filter = request.GET.get('categoria', '')

        if search_query:
            barcos = barcos.filter(Q(nombre__icontains=search_query))

        if categoria_filter:
            barcos = barcos.filter(categoria_id=categoria_filter)

        context = {
            'barcos': barcos,
            'categorias': categorias,
            'search_query': search_query,
            'categoria_filter': categoria_filter,
        }
        return render(request, 'catalog/list.html', context)


class BarcoDetailView(View):
    """Vista para mostrar detalles de un barco."""

    def get(self, request, id):
        barco = get_object_or_404(Barco, id=id)
        context = {'barco': barco}
        return render(request, 'catalog/detail.html', context)

from django.shortcuts import render, redirect
from django.views import View
from django.contrib.auth.models import User
from django.contrib.auth import authenticate, login, logout
from django.contrib.auth.decorators import login_required
from django.utils.decorators import method_decorator
from django.contrib import messages
from .forms import RegisterForm, LoginForm


class RegisterView(View):
    """Vista para registro de usuario."""

    def get(self, request):
        form = RegisterForm()
        return render(request, 'accounts/register.html', {'form': form})

    def post(self, request):
        form = RegisterForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']
            user = User.objects.create_user(username=email, email=email, password=password)
            login(request, user)
            messages.success(request, 'Registro exitoso. Bienvenido.')
            return redirect('/')
        return render(request, 'accounts/register.html', {'form': form})


class LoginView(View):
    """Vista para inicio de sesión."""

    def get(self, request):
        form = LoginForm()
        return render(request, 'accounts/login.html', {'form': form})

    def post(self, request):
        form = LoginForm(request.POST)
        if form.is_valid():
            email = form.cleaned_data['email']
            password = form.cleaned_data['password']
            user = authenticate(request, username=email, password=password)
            if user is not None:
                login(request, user)
                messages.success(request, 'Inicio de sesión exitoso.')
                return redirect('/')
            else:
                messages.error(request, 'Correo o contraseña incorrectos.')
        return render(request, 'accounts/login.html', {'form': form})


class LogoutView(View):
    """Vista para cierre de sesión."""

    @method_decorator(login_required)
    def get(self, request):
        logout(request)
        messages.success(request, 'Sesión cerrada correctamente.')
        return redirect('/')


class AccountView(View):
    """Vista para mostrar la cuenta del usuario."""

    @method_decorator(login_required)
    def get(self, request):
        return render(request, 'accounts/account.html', {'user': request.user})

