"""Servicios para gestión de cesta de compra."""


def get_cart(request):
    """Obtiene la cesta de la sesión."""
    if 'cart' not in request.session:
        request.session['cart'] = {}
    return request.session['cart']


def add_to_cart(request, barco_id, cantidad):
    """Añade un barco a la cesta."""
    cart = get_cart(request)
    barco_id_str = str(barco_id)
    if barco_id_str in cart:
        cart[barco_id_str]['cantidad'] += cantidad
    else:
        cart[barco_id_str] = {'cantidad': cantidad}
    request.session['cart'] = cart
    request.session.modified = True


def remove_from_cart(request, barco_id):
    """Elimina un barco de la cesta."""
    cart = get_cart(request)
    barco_id_str = str(barco_id)
    if barco_id_str in cart:
        del cart[barco_id_str]
    request.session['cart'] = cart
    request.session.modified = True


def update_cart_quantity(request, barco_id, cantidad):
    """Actualiza la cantidad de un barco en la cesta."""
    cart = get_cart(request)
    barco_id_str = str(barco_id)
    if barco_id_str in cart:
        if cantidad > 0:
            cart[barco_id_str]['cantidad'] = cantidad
        else:
            del cart[barco_id_str]
    request.session['cart'] = cart
    request.session.modified = True


def clear_cart(request):
    """Vacía la cesta."""
    request.session['cart'] = {}
    request.session.modified = True

from django.shortcuts import render, redirect
from django.views import View
from django.contrib import messages
from django.views.decorators.http import require_http_methods
from django.utils.decorators import method_decorator
from catalog.models import Barco
from .services import get_cart, add_to_cart, remove_from_cart, update_cart_quantity, clear_cart


class CartView(View):
    """Vista para mostrar la cesta de compra."""

    def get(self, request):
        cart = get_cart(request)
        cart_items = []
        total = 0

        for barco_id_str, item in cart.items():
            try:
                barco = Barco.objects.get(id=int(barco_id_str))
                cantidad = item['cantidad']
                subtotal = barco.precio_dia * cantidad
                total += subtotal
                cart_items.append({
                    'barco': barco,
                    'cantidad': cantidad,
                    'subtotal': subtotal,
                })
            except Barco.DoesNotExist:
                pass

        context = {
            'cart_items': cart_items,
            'total': total,
        }
        return render(request, 'cart/view.html', context)


class AddToCartView(View):
    """Vista para añadir un barco a la cesta."""

    def post(self, request):
        barco_id = request.POST.get('barco_id')
        cantidad = request.POST.get('cantidad', 1)

        try:
            barco_id = int(barco_id)
            cantidad = int(cantidad)
            barco = Barco.objects.get(id=barco_id)

            if cantidad > 0 and cantidad <= barco.disponibilidad:
                add_to_cart(request, barco_id, cantidad)
                messages.success(request, f'{barco.nombre} añadido a la cesta.')
            else:
                messages.error(request, 'Cantidad inválida.')
        except (ValueError, Barco.DoesNotExist):
            messages.error(request, 'Barco no encontrado.')

        return redirect('cart:view')


class UpdateCartView(View):
    """Vista para actualizar la cantidad de un barco en la cesta."""

    def post(self, request):
        barco_id = request.POST.get('barco_id')
        cantidad = request.POST.get('cantidad', 1)

        try:
            barco_id = int(barco_id)
            cantidad = int(cantidad)
            barco = Barco.objects.get(id=barco_id)

            if cantidad > 0 and cantidad <= barco.disponibilidad:
                update_cart_quantity(request, barco_id, cantidad)
                messages.success(request, 'Cesta actualizada.')
            elif cantidad == 0:
                remove_from_cart(request, barco_id)
                messages.success(request, 'Barco eliminado de la cesta.')
            else:
                messages.error(request, 'Cantidad inválida.')
        except (ValueError, Barco.DoesNotExist):
            messages.error(request, 'Barco no encontrado.')

        return redirect('cart:view')


class ClearCartView(View):
    """Vista para vaciar la cesta."""

    def post(self, request):
        clear_cart(request)
        messages.success(request, 'Cesta vaciada.')
        return redirect('cart:view')

